// Program.cs — add before builder.Build()

// Raise minimum worker/IOCP threads to prevent starvation during
// traffic bursts. The default scales with CPU count, which is often
// too low for I/O-heavy workloads.
ThreadPool.SetMinThreads(256, 256);

using Microsoft.AspNetCore.ResponseCompression;
using System.IO.Compression;

// Program.cs — register services
builder.Services.AddResponseCompression(options =>
{
    options.EnableForHttps = true;
    options.Providers.Add<BrotliCompressionProvider>();
    options.Providers.Add<GzipCompressionProvider>();
});

builder.Services.Configure<BrotliCompressionProviderOptions>(o =>
    o.Level = CompressionLevel.Fastest);

builder.Services.Configure<GzipCompressionProviderOptions>(o =>
    o.Level = CompressionLevel.Fastest);

// Add early in the middleware pipeline, before UseRouting
app.UseResponseCompression();

// Program.cs (.NET 7+)
builder.Services.AddOutputCache(options =>
{
    // Default policy: cache all GET/HEAD responses for 60 seconds
    options.AddBasePolicy(b => b.Expire(TimeSpan.FromSeconds(60)));

    // Named policy for longer-lived data
    options.AddPolicy("Long", b => b.Expire(TimeSpan.FromMinutes(10)));
});

// Add after UseRouting, before MapRazorPages / MapControllers
app.UseOutputCache();

// Minimal API — apply named policy to an endpoint:
// app.MapGet("/products", GetProducts).CacheOutput("Long");

// MVC / Razor Pages action attribute:
// [OutputCache(Duration = 60)]

// Program.cs
builder.WebHost.ConfigureKestrel(options =>
{
    // Cap total concurrent TCP connections (default: unlimited)
    options.Limits.MaxConcurrentConnections = 1000;
    options.Limits.MaxConcurrentUpgradedConnections = 1000;

    // Keep-alive idle timeout (Kestrel default: 130 s)
    options.Limits.KeepAliveTimeout = TimeSpan.FromSeconds(120);

    // Time allowed for client to send request headers (default: 30 s)
    options.Limits.RequestHeadersTimeout = TimeSpan.FromSeconds(15);
});

// Prevents socket exhaustion and respects DNS TTL changes.
// Register in Program.cs:

builder.Services.AddHttpClient("api", client =>
{
    client.BaseAddress = new Uri("https://api.example.com");
    client.Timeout = TimeSpan.FromSeconds(30);
})
.ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
{
    // Recycle connections after 2 minutes to pick up DNS changes
    PooledConnectionLifetime = TimeSpan.FromMinutes(2),
    PooledConnectionIdleTimeout = TimeSpan.FromSeconds(90),
    MaxConnectionsPerServer = 20,
    EnableMultipleHttp2Connections = true
});

